html_structure:
{% load static %}
<div class="resume-root">
  <header>
    <h1>{{ resume.basics.name }}</h1>
    <p class="title">{{ resume.basics.label }}</p>
    <p class="contact">{{ resume.basics.email }}{% if resume.basics.phone %} â¢ {{ resume.basics.phone }}{% endif %}</p>
  </header>

  {% if resume.basics.summary %}
  <section class="summary">
    <h2>Summary</h2>
    <p>{{ resume.basics.summary }}</p>
  </section>
  {% endif %}

  {% if resume.education %}
  <section class="education">
    <h2>Education</h2>
    <ul>
      {% for edu in resume.education %}
        <li>
          <strong>{{ edu.institution }}</strong>
          {% if edu.studyType %}<span class="degree"> â {{ edu.studyType }}</span>{% endif %}
          {% if edu.startDate or edu.endDate %}
            <div class="dates">{{ edu.startDate }} â {{ edu.endDate }}</div>
          {% endif %}
          {% if edu.area %}<div class="area">{{ edu.area }}</div>{% endif %}
        </li>
      {% endfor %}
    </ul>
  </section>
  {% endif %}

  {% if resume.skills %}
  <section class="skills">
    <h2>Skills</h2>
    <ul>
      {% for s in resume.skills %}
        <li>
          <strong>{{ s.name }}</strong>
          {% if s.keywords %}<div class="keywords">{{ s.keywords }}</div>{% endif %}
        </li>
      {% endfor %}
    </ul>
  </section>
  {% endif %}

  {% if resume.references %}
  <section class="references">
    <h2>References</h2>
    <ul>
      {% for r in resume.references %}
        <li>
          <strong>{{ r.name }}</strong>
          <div class="reference">{{ r.reference }}</div>
        </li>
      {% endfor %}
    </ul>
  </section>
  {% endif %}
</div>
